{"reasoning":"The stale greeting happens because update_profile only updates cached_greeting when the name changes, but does nothing when email changes. The profile invariant says changing email must also set verified=False and clear cached_greeting, so the fix is to invalidate the cache on any valid email update. Since build_greeting only depends on the user's name, clearing cached_greeting ensures downstream code won't keep showing an old greeting after email changes, and the user can be re-verified as intended.","plan":["Update the email branch in update_profile to set verified to False after a valid email change.","Clear cached_greeting when email changes so the old greeting is not retained."],"code":""""User profile with email verification and cached greeting."""

from validation import validate_email, validate_name
from notifications import build_greeting, should_reverify


def create_user(name, email):
    """Create a user with verified status and cached greeting."""
    return {
        "name": name,
        "email": email,
        "verified": False,
        "cached_greeting": build_greeting({"name": name}),
    }


def verify_user(user):
    """Mark user as verified."""
    user["verified"] = True
    return user


def update_profile(user, changes):
    """Update profile fields.

    Invariant: changing email must set verified=False and clear cached_greeting.
    Invariant: changing name must update cached_greeting.
    """
    for key, value in changes.items():
        if key == "email" and validate_email(value):
            old_email = user.get("email")
            user["email"] = value
            if should_reverify(old_email, value):
                user["verified"] = False
                user["cached_greeting"] = None
        elif key == "name" and validate_name(value):
            user["name"] = value
            user["cached_greeting"] = build_greeting(user)
    return user
"}

