{"reasoning":"The bug is that process() immediately drops items when called before init(). To make processing independent of arrival order, items should be buffered until initialization happens, then flushed in order. shutdown() should also ensure any remaining buffered items are processed so nothing is lost. This preserves correct behavior for already-initialized cases and fixes the out-of-order case by replaying queued items once init() occurs.","plan":["Add a queue for items received before initialization.","Have init() mark initialized and flush any buffered items, and ensure shutdown() also flushes pending items before logging shutdown."],"code":""""Pipeline with ordering dependency: process must run after init."""

_log = []
_initialized = False
_buffer = []


def reset():
    global _initialized
    _log.clear()
    _buffer.clear()
    _initialized = False


def _flush_buffer():
    """Process any buffered items now that initialization has happened."""
    global _buffer
    while _buffer:
        item = _buffer.pop(0)
        _log.append(f"processed:{item}")


def init():
    global _initialized
    _initialized = True
    _log.append("init")
    _flush_buffer()


def process(item):
    """Process items regardless of arrival order by buffering until init."""
    if not _initialized:
        _buffer.append(item)
        _log.append(f"buffered:{item}")
        return False
    _log.append(f"processed:{item}")
    return True


def shutdown():
    if not _initialized and _buffer:
        # If shutdown happens before init, preserve items by flushing them anyway.
        _initialized = True
    _flush_buffer()
    _log.append("shutdown")
    return list(_log)


def get_log():
