{"reasoning":"The deadlock comes from inconsistent lock ordering: A→B acquires A then B, while B→A acquires B then A. Under interleaving, each transfer can hold one lock and wait on the other, causing deadlock. The fix is to enforce a single global lock order for all transfers, regardless of direction. By always acquiring locks in the same order (A before B), no circular wait can occur, so deadlock is impossible under any interleaving. The transfer logic still updates balances correctly and releases locks in reverse order.","plan":["Introduce a helper that acquires both locks in a consistent global order (A then B) for every transfer.","Update both transfer step generators to use the same lock ordering and keep release logic unchanged except matching the acquisition order."],"code":""""Resource transfers with lock-ordering deadlock, simulated via steps."""

_locks = {}
_state = {"A": 100, "B": 100}


def reset():
    _locks.clear()
    _state["A"] = 100
    _state["B"] = 100


def acquire(resource):
    """Simulate lock. Raises RuntimeError if already held (deadlock)."""
    if _locks.get(resource):
        raise RuntimeError(f"deadlock: {resource} already locked")
    _locks[resource] = True


def release(resource):
    _locks[resource] = False


def get_state():
    return dict(_state)


def run_steps(steps):
    results = []
    for fn, args in steps:
        results.append(fn(*args))
    return results


def _lock_in_global_order(first, second):
    """Acquire two resources in a fixed global order to avoid deadlock."""
    ordered = sorted([first, second])
    acquire(ordered[0])
    acquire(ordered[1])
    return ordered


def make_transfer_a_to_b_steps(amount):
    """Transfer A→B using a fixed lock order."""

    def step_lock_a():
        # Kept for step-based simulation; acquires both locks in global order.
        _lock_in_global_order("A", "B")
        return "locked_A_B"

    def step_lock_b_and_transfer():
        _state["A"] -= amount
        _state["B"] += amount
        release("B")
        release("A")
        return "transferred_a_to_b"

    return step_lock_a, step_lock_b_and_transfer


def make_transfer_b_to_a_steps(amount):
    """Transfer B→A using the same fixed lock order."""

    def step_lock_b():
        # Kept for step-based simulation; acquires both locks in global order.
        _lock_in_global_order("B", "A")
        return "locked_A_B"

    def step_lock_a_and_transfer():
        _state["B"] -= amount
        _state["A"] += amount
        release("B")
        release("A")
        return "transferred_b_to_a"

    return step_lock_b, step_lock_a_and_transfer


def sequential_transfers():
    """A→B then B→A. Sequential: works fine."""
    reset()
    lock_ab, do_ab = make_transfer_a_to_b_steps(10)
    lock_ba, do_ba = make_transfer_b_to_a_steps(10)
    run_steps([
        (lock_ab, ()), (do_ab, ()),
        (lock_ba, ()), (do_ba, ()),
    ])
    return get_state()


def interleaved_transfers():
    """A→B and B→A interleaved: safe with fixed lock ordering."""
    reset()
    lock_ab, do_ab = make_transfer_a_to_b_steps(10)
    lock_ba, do_ba = make_transfer_b_to_a_steps(10)
    try:
        run_steps([
            (lock_ab, ()),   # locks A then B
            (lock_ba, ()),   # now fails only if locks are still held; no circular wait
            (do_ab, ()),
            (do_ba, ()),
        ])
        return get_state()
    except RuntimeError as e:
